#### Game Module (`game.py`):

```python
"""
Manages the overall game state and controls the flow of gameplay.
"""

class Game:
    def __init__(self):
        self.board = Board()

    def run(self):
        while True:
            self.board.display()
            from_pos = input("Player 1, enter your move (from-to): ")
            if self.board.make_move(from_pos, to_pos):
                break
```

#### Board Module (`board.py`):

```python
"""
Represents the 8x8 checkers board and handles all board-related operations.
"""

class Board:
    def __init__(self):
        self.grid = [[None for _ in range(8)] for _ in range(8)]
        self.init_board()

    def init_board(self):
        # Initialize pieces on the board
        colors = ['R', 'B']
        for color, row in zip(colors, (0, 7)):
            for i in range(3):
                self.grid[row][i * 2] = Piece(color, False)
                self.grid[7 - row][6 - i * 2] = Piece(color, False)

    def display(self):
        # Display the board
        print("   A B C D E F G H")
        for i, row in enumerate(self.grid):
            line = f"{8 - i} "
            for piece in row:
                if piece is None:
                    line += ". "
                else:
                    line += piece.symbol + " "
            print(line)

    def make_move(self, from_pos, to_pos):
        # Implement move logic
        pass

class Piece:
    def __init__(self, color, king=False):
        self.color = color
        self.king = king
        self.symbol = 'K' if king else ('R' if color == 'R' else 'B')

    def move(self, to_pos):
